// Formatear testimonios con logica de ratio (60/20/10) y antiguedad
const records = $input.first().json.records || [];

if (records.length === 0) {
  return [{ json: {
    testimonios: [],
    total: 0,
    mensaje: 'Sin testimonios disponibles'
  }}];
}

// Auxiliares
const shuffle = (array) => array.sort(() => Math.random() - 0.5);

function tiempoRelativo(fecha) {
  const ahora = new Date();
  const creado = new Date(fecha);
  const diffMs = ahora - creado;
  const diffDias = Math.floor(diffMs / (1000 * 60 * 60 * 24));
  if (diffDias === 0) return 'Hoy';
  if (diffDias === 1) return 'Ayer';
  if (diffDias < 7) return `Hace ${diffDias} días`;
  if (diffDias < 30) return `Hace ${Math.floor(diffDias / 7)} semanas`;
  return `Hace ${Math.floor(diffDias / 30)} meses`;
}

function getIniciales(nombre) {
  if (!nombre) return '?';
  const partes = nombre.trim().split(' ');
  return (partes[0].charAt(0) + (partes.length > 1 ? partes[partes.length - 1].charAt(0) : '')).toUpperCase();
}

// Mapeo inicial
const todos = records.map(r => ({
  id: r.id,
  nombre: r.fields.NOMBRE || 'Anónimo',
  iniciales: getIniciales(r.fields.NOMBRE),
  estrellas: r.fields.ESTRELLAS || 0,
  comentario: r.fields.COMENTARIO || '',
  fechaRaw: new Date(r.fields['FECHA DE CREACION']),
  fecha: tiempoRelativo(r.fields['FECHA DE CREACION']),
  fotoUrl: (r.fields['USAR FOTO'] && r.fields['FOTO PERFIL'] && r.fields['FOTO PERFIL'].length > 0) ? r.fields['FOTO PERFIL'][0].url : null
}));

// Categorizar por estrellas
const buenos = todos.filter(t => t.estrellas >= 3);
const medios = todos.filter(t => t.estrellas === 2);
const bajos = todos.filter(t => t.estrellas === 1);

// Seleccion inteligente por ratio (objetivo 10)
// 60% Buenos (6), 20% Medios (2), 10% Bajos (1), 1 Extra
const seleccionados = [];

function pick(source, count) {
  const recent = source.slice(0, Math.max(source.length, count * 2));
  return shuffle(recent).slice(0, count);
}

seleccionados.push(...pick(buenos, 7)); 
seleccionados.push(...pick(medios, 2));
seleccionados.push(...pick(bajos, 1));

if (seleccionados.length < 10) {
  const rest = buenos.filter(b => !seleccionados.find(s => s.id === b.id));
  seleccionados.push(...pick(rest, 10 - seleccionados.length));
}

const final = shuffle(seleccionados);

return [{ json: {
  testimonios: final,
  total: final.length,
  mensaje: `Mostrando una mezcla de ${final.length} opiniones` 
}}];
